SELECT [Sales Header].[Selling Season Code], [Sales Header].[Bill-to Customer No_], [Sales Header].[Bill-to Name], [Sales Header].No_, [Sales Header].[Ship-to Code], Customer.County AS ProvinciaAnagraficaCliente, [Ship-to Address].County AS ProvinciaShipToAnagrafica, [Sales Header].[Bill-to County], [Sales Header].[Sell-to County], [Sales Header].[Ship-to County]
FROM ([Sales Header] INNER JOIN Customer ON [Sales Header].[Sell-to Customer No_] = Customer.No_) LEFT JOIN [Ship-to Address] ON ([Sales Header].[Sell-to Customer No_] = [Ship-to Address].[Customer No_]) AND ([Sales Header].[Ship-to Code] = [Ship-to Address].Code)
WHERE ((([Sales Header].[Selling Season Code])=[Codice Stagione]) AND ((Len([customer].[county]))>2)) OR ((([Sales Header].[Selling Season Code])=[Codice Stagione]) AND ((Len([Ship-to Address].[County]))>2)) OR ((([Sales Header].[Selling Season Code])=[Codice Stagione]) AND ((Len([Sales Header].[Bill-to County]))>2)) OR ((([Sales Header].[Selling Season Code])=[Codice Stagione]) AND ((Len([Sales Header].[Sell-to County]))>2)) OR ((([Sales Header].[Selling Season Code])=[Codice Stagione]) AND ((Len([Sales Header].[Ship-to County]))>2));

